export const getRating = async (opponentId) => {
    let rating;
    const response = await fetch(`${FIREBASE_DATABASE_URL}/users/${opponentId}/gamesPlayed/heroes3.json`, {
        method: 'GET'
    });

    const data = await response.json();

    if (data) {
        const totalGames = data.total;
        const victories = data.total - data.lose;
        const winRatio = victories / totalGames;

        rating = winRatio * 5 + totalGames * 0.5;
    }

    return rating;
};

export const getNewRating = (playerRating, opponentRating, didWin, kFactor = 1) => {
    // ELO expected score.
    // Divisor is tuned for this game's rating scale (~3–20 range).
    // A 5-point difference gives ~75% expected win for the higher-rated player.
    const expectedScore = 1 / (1 + Math.pow(10, (opponentRating - playerRating) / 10));

    // Standard ELO actual scores: 1 for a win, 0 for a loss.
    // Previously 0.7/0.3 which incorrectly gave rating gains even after a loss.
    const actualScore = didWin ? 1 : 0;

    // Rating change: positive when you outperform expectation, negative when you underperform.
    // Beating a much stronger player → big gain. Losing to a much weaker player → big loss.
    let ratingChange = kFactor * (actualScore - expectedScore);

    // Symmetric cap to prevent extreme swings (e.g. on first game with rating 0).
    ratingChange = Math.max(-2.5, Math.min(ratingChange, 2.5));

    return enforceMinPlayerRating(playerRating + ratingChange);
};

export const SITE_STARS_MAX = 5;
export const SITE_STARS_MIN = 0.5;
export const SITE_STARS_TOP50_COUNT = 50;
export const SITE_STARS_TOP50_MIN = 4;

export const roundSiteStars = (value) => {
    const clamped = Math.max(SITE_STARS_MIN, Math.min(SITE_STARS_MAX, value));
    return Math.round(clamped * 2) / 2;
};

export const computeSiteStarsFromRank = (rank, { topCount = SITE_STARS_TOP50_COUNT } = {}) => {
    if (rank == null || rank <= 0) {
        return SITE_STARS_MIN;
    }

    if (rank <= topCount) {
        const progress = (rank - 1) / Math.max(topCount - 1, 1);
        return roundSiteStars(SITE_STARS_MAX - progress * (SITE_STARS_MAX - SITE_STARS_TOP50_MIN));
    }

    if (rank <= 150) {
        const progress = (rank - topCount) / (150 - topCount);
        return roundSiteStars(SITE_STARS_TOP50_MIN - progress * 1);
    }

    if (rank <= 500) {
        const progress = (rank - 150) / (500 - 150);
        return roundSiteStars(3 - progress * 1.5);
    }

    return SITE_STARS_MIN;
};

export const applySiteStarsFromRank = (players) =>
    players.map((player) => ({
        ...player,
        siteStars: computeSiteStarsFromRank(player.rank)
    }));

export const getSiteStarBounds = (players, ratingKey = 'rating') => {
    const ratings = players
        .map((player) => Number(player?.[ratingKey]))
        .filter((rating) => Number.isFinite(rating) && rating > 0);

    if (!ratings.length) {
        return { highest: 0, lowest: 0 };
    }

    return {
        highest: Math.max(...ratings),
        lowest: Math.min(...ratings)
    };
};

export const computeSiteStars = (rating, bounds, minStars = SITE_STARS_MIN) => {
    if (!bounds || (!bounds.highest && !bounds.lowest)) {
        return minStars;
    }

    return calculateStarsFromRating(Number(rating) || 0, bounds.highest, bounds.lowest, minStars);
};

export const applySiteStarsToPlayers = (players, bounds, ratingKey = 'rating') =>
    players.map((player) => ({
        ...player,
        siteStars: computeSiteStars(player?.[ratingKey], bounds)
    }));

export const calculateStarsFromRating = (rating, highestRating, lowestRating, minStars = SITE_STARS_MIN) => {
    let cappedStars;
    if (rating > 0) {
        const totalStars = SITE_STARS_MAX;
        const range = highestRating - lowestRating;

        // Linear distribution from 0.5 to 5.0 stars
        const normalized = range === 0 ? 1 : (rating - lowestRating) / range;
        const rawStars = normalized * (totalStars - minStars) + minStars;

        console.log(
            `calculateStarsFromRating: rating=${rating}, highest=${highestRating}, lowest=${lowestRating}, minStars=${minStars}, normalized=${normalized}, rawStars=${rawStars}`
        );

        cappedStars = Math.round(rawStars * 2) / 2; // Round to nearest 0.5
        cappedStars = Math.min(cappedStars, totalStars); // Cap stars at 5

        console.log(`Final capped stars: ${cappedStars}`);
    } else {
        cappedStars = minStars;
    }

    if (+cappedStars < minStars) {
        cappedStars = minStars;
    }

    return cappedStars;
};

