export const determineTournamentPrizes = (total_prize) => {
    let prizes = {};
    // Calculate prize amounts for each place
    prizes['1st Place'] = (total_prize * 0.6).toFixed(2);
    prizes['2nd Place'] = (total_prize * 0.3).toFixed(2);
    prizes['3rd Place'] = (total_prize * 0.1).toFixed(2);
    return prizes;
};

export const pullTournamentPrizes = async (tournamentId) => {
    const tournamentResponse = await fetch(`${FIREBASE_DATABASE_URL}/tournaments/heroes3/${tournamentId}.json`);
    if (!tournamentResponse.ok) {
        return null;
    }

    const tournament = await tournamentResponse.json();
    const goldPrizes = buildUsdPrizesFromFunding(tournament);
    if (goldPrizes) {
        return goldPrizes;
    }

    if (tournament?.pricePull) {
        return tournament.pricePull;
    }

    return null;
};

